1	package docprose
2	
3	import (
4		"fmt"
5		"regexp"
6		"strings"
7		"unicode"
8	)
9	
10	type Mode string
11	
12	const (
13		ModeTechnical Mode = "technical"
14		ModePlanning  Mode = "planning"
15		ModePublic    Mode = "public"
16	)
17	
18	type Checker struct {
19		mode       Mode
20		rules      []ruleSpec
21		vocabulary Vocabulary
22	}
23	
24	func NewChecker(mode Mode, vocabulary Vocabulary) (*Checker, error) {
25		if mode == "" {
26			mode = ModeTechnical
27		}
28		rules, err := loadRulePack(string(mode))
29		if err != nil {
30			return nil, err
31		}
32		defaultVocab, err := loadDefaultVocabulary()
33		if err != nil {
34			return nil, err
35		}
36		if len(vocabulary.Accept) == 0 {
37			vocabulary.Accept = defaultVocab.Accept
38		}
39		if len(vocabulary.Reject) == 0 {
40			vocabulary.Reject = defaultVocab.Reject
41		}
42		return &Checker{
43			mode:       mode,
44			rules:      rules,
45			vocabulary: vocabulary,
46		}, nil
47	}
48	
49	func (c *Checker) Findings(file, text string) []Finding {
50		var findings []Finding
51		lines := strings.Split(text, "\n")
52	
53		for idx, raw := range lines {
54			lineNo := idx + 1
55			line := strings.TrimSpace(raw)
56			if line == "" {
57				continue
58			}
59	
60			for _, rule := range c.rules {
61				if rule.Kind == "repeated_opening" {
62					if repeatedOpeningKey(line) != "" {
63						findings = append(findings, Finding{
64							File:          file,
65							Line:          lineNo,
66							RuleID:        rule.ID,
67							Severity:      rule.Severity,
68							Rationale:     rule.Rationale,
69							SuggestedEdit: rule.SuggestedEdit,
70						})
71					}
72					continue
73				}
74				if matchesRule(line, rule) {
75					findings = append(findings, Finding{
76						File:          file,
77						Line:          lineNo,
78						RuleID:        rule.ID,
79						Severity:      rule.Severity,
80						Rationale:     rule.Rationale,
81						SuggestedEdit: rule.SuggestedEdit,
82					})
83				}
84			}
85	
86			findings = append(findings, c.vocabularyFindings(file, lineNo, line)...)
87		}
88	
89		return findings
90	}
91	
92	func (c *Checker) vocabularyFindings(file string, lineNo int, line string) []Finding {
93		var findings []Finding
94		lower := strings.ToLower(line)
95		for _, reject := range c.vocabulary.Reject {
96			if reject == "" {
97				continue
98			}
99			if !containsWord(lower, reject) {
100				continue
101			}
102			if c.termAccepted(reject) {
103				continue
104			}
105			findings = append(findings, Finding{
106				File:          file,
107				Line:          lineNo,
108				RuleID:        "prose.vocabulary.reject",
109				Severity:      "warning",
110				Rationale:     fmt.Sprintf("The vocabulary term %q is discouraged in default prose because it is too generic.", reject),
111				SuggestedEdit: fmt.Sprintf("Replace %q with the project-specific term or concrete noun that names the actual concept.", reject),
112			})
113		}
114		return findings
115	}
116	
117	func (c *Checker) termAccepted(term string) bool {
118		for _, accept := range c.vocabulary.Accept {
119			if accept == "" {
120				continue
121			}
122			if strings.EqualFold(strings.TrimSpace(accept), strings.TrimSpace(term)) {
123				return true
124			}
125		}
126		return false
127	}
128	
129	func matchesRule(line string, rule ruleSpec) bool {
130		if len(rule.ContainsAny) == 0 {
131			return false
132		}
133		if isMarkdownStructureLine(line) {
134			return false
135		}
136		lower := strings.ToLower(line)
137		matched := false
138		for _, phrase := range rule.ContainsAny {
139			if phrase == "" {
140				continue
141			}
142			if strings.Contains(lower, strings.ToLower(phrase)) {
143				matched = true
144				break
145			}
146		}
147		if !matched {
148			return false
149		}
150		if strings.HasSuffix(rule.ID, ".claims") {
151			return unsupportedClaim(line)
152		}
153		return true
154	}
155	
156	func isMarkdownStructureLine(line string) bool {
157		trimmed := strings.TrimSpace(line)
158		if trimmed == "" {
159			return true
160		}
161		if strings.HasPrefix(trimmed, "#") || strings.HasPrefix(trimmed, "---") {
162			return true
163		}
164		if strings.HasPrefix(trimmed, "|") && strings.HasSuffix(trimmed, "|") {
165			return true
166		}
167		if strings.Contains(trimmed, ".md") || strings.Contains(trimmed, ".yaml") || strings.Contains(trimmed, ".json") {
168			return true
169		}
170		if strings.HasPrefix(trimmed, "- ") && len(strings.Fields(trimmed)) <= 8 {
171			return true
172		}
173		return false
174	}
175	
176	func unsupportedClaim(line string) bool {
177		lower := strings.ToLower(line)
178		if containsAny(lower, []string{
179			"seamless",
180			"industry-leading",
181			"world-class",
182			"best-in-class",
183			"cutting-edge",
184		}) {
185			return true
186		}
187		if unsupportedComprehensiveClaim(lower) {
188			return true
189		}
190		if hasEmpiricalOrCheckContext(lower) {
191			return false
192		}
193		if unsupportedBenefitClaim(lower) {
194			return true
195		}
196		if countMatches(lower, []string{"robust", "comprehensive", "smooth", "elegant", "excited", "high"}) >= 2 {
197			return true
198		}
199		if countWords(line) <= 8 {
200			return true
201		}
202		return containsAny(lower, []string{
203			"experience for everyone",
204			"path forward",
205			"broadly useful",
206			"easy to adopt",
207		})
208	}
209	
210	func unsupportedComprehensiveClaim(lower string) bool {
211		if !strings.Contains(lower, "comprehensive") {
212			return false
213		}
214		return containsAny(lower, []string{
215			"comprehensive prd",
216			"comprehensive implementation plan",
217			"comprehensive plan",
218			"comprehensive checklist",
219			"comprehensive checklists",
220			"comprehensive tests",
221			"comprehensive documentation",
222		})
223	}
224	
225	func unsupportedBenefitClaim(lower string) bool {
226		return containsAny(lower, []string{
227			"better alignment",
228			"better pattern",
229			"better tools",
230			"complex problems",
231			"cutting edge",
232			"powerful commands",
233			"productive ways",
234			"sophisticated autonomous",
235			"sophisticated control flow",
236			"sophisticated multi-agent",
237			"true power",
238		})
239	}
240	
241	func hasEmpiricalOrCheckContext(lower string) bool {
242		return containsAny(lower, []string{
243			"reproduced",
244			"measured",
245			"benchmark",
246			"test",
247			"coverage",
248			"contract",
249			"verifiable",
250			"quality-lifting pattern",
251			"risk",
252			"mitigation",
253		})
254	}
255	
256	func containsAny(s string, needles []string) bool {
257		for _, needle := range needles {
258			if strings.Contains(s, needle) {
259				return true
260			}
261		}
262		return false
263	}
264	
265	func countMatches(s string, needles []string) int {
266		var count int
267		for _, needle := range needles {
268			if strings.Contains(s, needle) {
269				count++
270			}
271		}
272		return count
273	}
274	
275	func countWords(s string) int {
276		return len(strings.Fields(s))
277	}
278	
279	func repeatedOpeningKey(line string) string {
280		first, rest, ok := cutSentence(line)
281		if !ok {
282			return ""
283		}
284		second, _, ok := cutSentence(rest)
285		if !ok {
286			return ""
287		}
288		first = normalizeSentence(first)
289		second = normalizeSentence(second)
290		if first == "" || first != second {
291			return ""
292		}
293		return first
294	}
295	
296	func cutSentence(s string) (head, tail string, ok bool) {
297		s = strings.TrimSpace(s)
298		if s == "" {
299			return "", "", false
300		}
301		for i, r := range s {
302			if r == '.' || r == '!' || r == '?' {
303				return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
304			}
305		}
306		return "", "", false
307	}
308	
309	func normalizeSentence(s string) string {
310		s = strings.ToLower(strings.TrimSpace(s))
311		s = strings.TrimFunc(s, func(r rune) bool {
312			return unicode.IsPunct(r) || unicode.IsSpace(r)
313		})
314		s = strings.Join(strings.Fields(s), " ")
315		return s
316	}
317	
318	func containsWord(haystack, needle string) bool {
319		needle = strings.TrimSpace(needle)
320		if needle == "" {
321			return false
322		}
323		pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
324		return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
325	}
