1	package docprose
2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"strings"
8	)
9	
10	// TempValeConfig holds paths to a temporary Vale configuration scoped to one invocation.
11	type TempValeConfig struct {
12		dir     string
13		iniPath string
14	}
15	
16	// INIPath returns the path to the generated .vale.ini file.
17	func (t *TempValeConfig) INIPath() string {
18		return t.iniPath
19	}
20	
21	// StylesPath returns the absolute styles directory written into the generated .vale.ini.
22	func (t *TempValeConfig) StylesPath() string {
23		return filepath.Join(t.dir, "styles")
24	}
25	
26	// Cleanup removes all temporary files created for this config.
27	func (t *TempValeConfig) Cleanup() {
28		os.RemoveAll(t.dir)
29	}
30	
31	// NewTempValeConfig generates a temporary Vale configuration from DDx settings.
32	// StylesPath is pointed at the packaged DDx styles via a symlink so no copy is needed.
33	// Project vocabulary is rendered into Vale accept/reject files under Vocab/Project/.
34	// The caller must call Cleanup() when done.
35	func NewTempValeConfig(settings Settings) (*TempValeConfig, error) {
36		assetRoot, err := defaultAssetRoot()
37		if err != nil {
38			return nil, fmt.Errorf("resolve asset root: %w", err)
39		}
40		packagedDDxStyles := filepath.Join(assetRoot, "styles", "DDx")
41	
42		dir, err := os.MkdirTemp("", "ddx-vale-")
43		if err != nil {
44			return nil, fmt.Errorf("create temp vale dir: %w", err)
45		}
46	
47		stylesDir := filepath.Join(dir, "styles")
48		if err := os.MkdirAll(stylesDir, 0o755); err != nil {
49			os.RemoveAll(dir)
50			return nil, fmt.Errorf("create styles dir: %w", err)
51		}
52	
53		// Symlink the packaged DDx style directory so we avoid copying rule files.
54		if err := os.Symlink(packagedDDxStyles, filepath.Join(stylesDir, "DDx")); err != nil {
55			os.RemoveAll(dir)
56			return nil, fmt.Errorf("symlink DDx styles: %w", err)
57		}
58	
59		vocabName := ""
60		if len(settings.Vocabulary.Accept) > 0 || len(settings.Vocabulary.Reject) > 0 {
61			vocabName = "Project"
62			vocabDir := filepath.Join(stylesDir, "Vocab", vocabName)
63			if err := os.MkdirAll(vocabDir, 0o755); err != nil {
64				os.RemoveAll(dir)
65				return nil, fmt.Errorf("create vocab dir: %w", err)
66			}
67			if err := writeTextLines(filepath.Join(vocabDir, "accept.txt"), settings.Vocabulary.Accept); err != nil {
68				os.RemoveAll(dir)
69				return nil, fmt.Errorf("write accept vocabulary: %w", err)
70			}
71			if err := writeTextLines(filepath.Join(vocabDir, "reject.txt"), settings.Vocabulary.Reject); err != nil {
72				os.RemoveAll(dir)
73				return nil, fmt.Errorf("write reject vocabulary: %w", err)
74			}
75		}
76	
77		style := settings.Vale.Style
78		if style == "" {
79			style = "DDx"
80		}
81	
82		iniPath := filepath.Join(dir, ".vale.ini")
83		ini := buildValeINI(stylesDir, style, vocabName)
84		if err := os.WriteFile(iniPath, []byte(ini), 0o644); err != nil {
85			os.RemoveAll(dir)
86			return nil, fmt.Errorf("write .vale.ini: %w", err)
87		}
88	
89		return &TempValeConfig{dir: dir, iniPath: iniPath}, nil
90	}
91	
92	func buildValeINI(stylesPath, style, vocabName string) string {
93		var b strings.Builder
94		fmt.Fprintf(&b, "StylesPath = %s\n", stylesPath)
95		fmt.Fprintf(&b, "MinAlertLevel = suggestion\n")
96		if vocabName != "" {
97			fmt.Fprintf(&b, "Vocab = %s\n", vocabName)
98		}
99		fmt.Fprintf(&b, "\n[*.md]\n")
100		fmt.Fprintf(&b, "BasedOnStyles = %s\n", style)
101		return b.String()
102	}
103	
104	func writeTextLines(path string, lines []string) error {
105		content := strings.Join(lines, "\n")
106		if len(lines) > 0 {
107			content += "\n"
108		}
109		return os.WriteFile(path, []byte(content), 0o644)
110	}
