1	package docprose
2	
3	import (
4		"os"
5		"path/filepath"
6		"strings"
7		"testing"
8	
9		ddxconfig "github.com/DocumentDrivenDX/ddx/internal/config"
10	)
11	
12	func TestProseCheckerFindingSchema(t *testing.T) {
13		checker, err := NewChecker(ModeTechnical, Vocabulary{})
14		if err != nil {
15			t.Fatal(err)
16		}
17		findings := checker.Findings("input.md", "This is robust.\n")
18		if len(findings) == 0 {
19			t.Fatal("expected at least one finding")
20		}
21		f := findings[0]
22		if f.File != "input.md" || f.Line != 1 || f.RuleID == "" || f.Severity == "" || f.Rationale == "" || f.SuggestedEdit == "" {
23			t.Fatalf("finding missing required field(s): %+v", f)
24		}
25	}
26	
27	func TestProseCheckerVocabularyOverrides(t *testing.T) {
28		checker, err := NewChecker(ModeTechnical, Vocabulary{
29			Accept: []string{"Quartz"},
30			Reject: []string{"system", "solution"},
31		})
32		if err != nil {
33			t.Fatal(err)
34		}
35	
36		findings := checker.Findings("input.md", "Quartz keeps the system solution honest.\n")
37		if len(findings) != 2 {
38			t.Fatalf("expected 2 reject findings, got %+v", findings)
39		}
40		for _, finding := range findings {
41			if finding.RuleID != "prose.vocabulary.reject" {
42				t.Fatalf("unexpected rule id: %+v", finding)
