215	func containsAll(got []string, want []string) bool {
216		m := make(map[string]bool, len(got))
217		for _, s := range got {
218			m[s] = true
219		}
220		for _, s := range want {
221			if !m[s] {
222				return false
223			}
224		}
225		return true
