12	type fixtureCase struct {
13		Name     string
14		Mode     string
15		Input    string
16		Golden   string
17		Findings []Finding
18	}
19	
20	func loadFixtureCase(t *testing.T, root, mode, name string) fixtureCase {
21		t.Helper()
22	
23		dir := filepath.Join(root, mode, name)
24		inputPath := filepath.Join(dir, "input.md")
25		goldenPath := filepath.Join(dir, "findings.golden.json")
26	
27		input, err := os.ReadFile(inputPath)
28		if err != nil {
29			t.Fatalf("read %s: %v", inputPath, err)
30		}
31		golden, err := os.ReadFile(goldenPath)
32		if err != nil {
33			t.Fatalf("read %s: %v", goldenPath, err)
34		}
35		var findings []Finding
36		if err := json.Unmarshal(golden, &findings); err != nil {
37			t.Fatalf("unmarshal %s: %v", goldenPath, err)
38		}
39		return fixtureCase{
40			Name:     name,
41			Mode:     mode,
42			Input:    string(input),
43			Golden:   strings.TrimSpace(string(golden)),
44			Findings: findings,
45		}
46	}
47	
48	func listFixtureCases(t *testing.T, root string) []fixtureCase {
49		t.Helper()
50	
51		modes, err := os.ReadDir(root)
52		if err != nil {
53			t.Fatalf("read fixture root %s: %v", root, err)
54		}
55	
56		var cases []fixtureCase
57		for _, modeEntry := range modes {
58			if !modeEntry.IsDir() {
59				continue
60			}
61			mode := modeEntry.Name()
62			modeDir := filepath.Join(root, mode)
63			names, err := os.ReadDir(modeDir)
64			if err != nil {
65				t.Fatalf("read mode dir %s: %v", modeDir, err)
66			}
67			for _, nameEntry := range names {
68				if !nameEntry.IsDir() {
69					continue
70				}
71				cases = append(cases, loadFixtureCase(t, root, mode, nameEntry.Name()))
72			}
73		}
74	
75		sort.Slice(cases, func(i, j int) bool {
76			if cases[i].Mode == cases[j].Mode {
77				return cases[i].Name < cases[j].Name
78			}
79			return cases[i].Mode < cases[j].Mode
80		})
81		return cases
82	}
83	
84	func TestFixtures(t *testing.T) {
85		const root = "testdata/fixtures"
86		cases := listFixtureCases(t, root)
87		if len(cases) == 0 {
88			t.Fatal("expected at least one docprose fixture case")
89		}
90	
91		seenModes := map[string]bool{}
92		for _, tc := range cases {
93			t.Run(tc.Mode+"/"+tc.Name, func(t *testing.T) {
94				seenModes[tc.Mode] = true
95				if strings.TrimSpace(tc.Input) == "" {
96					t.Fatalf("fixture input is empty")
97				}
98				if !strings.Contains(tc.Input, "\n") {
99					t.Fatalf("fixture input must be markdown with multiple lines")
100				}
101				if !strings.HasSuffix(tc.Golden, "]") {
102					t.Fatalf("golden must be a JSON array: %s", tc.Golden)
103				}
104	
105				checker, err := NewChecker(Mode(tc.Mode), Vocabulary{})
106				if err != nil {
107					t.Fatal(err)
108				}
109				got := checker.Findings("input.md", tc.Input)
110				if !sameFindings(got, tc.Findings) {
111					gotJSON, err := json.MarshalIndent(got, "", "  ")
112					if err != nil {
113						t.Fatalf("marshal got findings: %v", err)
114					}
115					t.Fatalf("fixture golden mismatch for %s/%s\n--- got ---\n%s\n--- want ---\n%s", tc.Mode, tc.Name, gotJSON, tc.Golden)
116				}
117	
118				for i, finding := range got {
119					if finding.File == "" || finding.Line == 0 || finding.RuleID == "" || finding.Severity == "" || finding.Rationale == "" || finding.SuggestedEdit == "" {
120						t.Fatalf("finding %d missing required field: %+v", i, finding)
121					}
122				}
123			})
124		}
125	
126		for _, mode := range []string{"technical", "planning", "public"} {
127			if !seenModes[mode] {
128				t.Fatalf("expected at least one fixture in %q mode", mode)
129			}
130		}
131	}
