279	func repeatedOpeningKey(line string) string {
280		first, rest, ok := cutSentence(line)
281		if !ok {
282			return ""
283		}
284		second, _, ok := cutSentence(rest)
285		if !ok {
286			return ""
287		}
288		first = normalizeSentence(first)
289		second = normalizeSentence(second)
290		if first == "" || first != second {
291			return ""
292		}
293		return first
294	}
295	
296	func cutSentence(s string) (head, tail string, ok bool) {
297		s = strings.TrimSpace(s)
298		if s == "" {
299			return "", "", false
300		}
301		for i, r := range s {
302			if r == '.' || r == '!' || r == '?' {
303				return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
304			}
305		}
306		return "", "", false
307	}
308	
309	func normalizeSentence(s string) string {
310		s = strings.ToLower(strings.TrimSpace(s))
311		s = strings.TrimFunc(s, func(r rune) bool {
312			return unicode.IsPunct(r) || unicode.IsSpace(r)
313		})
314		s = strings.Join(strings.Fields(s), " ")
315		return s
316	}
317	
318	func containsWord(haystack, needle string) bool {
319		needle = strings.TrimSpace(needle)
320		if needle == "" {
321			return false
322		}
323		pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
324		return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
325	}
